import { io, Socket } from 'socket.io-client';
import Constants from 'expo-constants';

const API_URL = Constants.expoConfig?.extra?.apiUrl || 'http://localhost:3001/api';
const SOCKET_URL = API_URL.replace('/api', '');

type SocketEvent =
  | 'authenticated'
  | 'disconnected'
  | 'connect_error'
  | 'error'
  | 'new_message'
  | 'message_notification'
  | 'user_typing'
  | 'message_read'
  | 'messages_read'
  | 'user_status'
  | 'joined_conversation'
  | 'message_edited'
  | 'message_reacted'
  | 'message_pinned'
  | 'conversation_pinned'
  | 'conversation_muted'
  | 'conversation_deleted'
  | 'homework_created'
  | 'leave_status_updated'
  | 'teacher_attendance_marked'
  | 'staff_updated';

type EventCallback = (data: any) => void;

class SocketService {
  private socket: Socket | null = null;
  private connected: boolean = false;
  private authenticated: boolean = false;
  private userId: string | null = null;
  private userType: 'staff' | 'student' | null = null;
  private listeners: Map<SocketEvent, EventCallback[]> = new Map();
  private reconnectAttempts: number = 0;
  private maxReconnectAttempts: number = 5;

  connect(userId: string, userType: 'staff' | 'student'): Promise<void> {
    // If already connected and authenticated, reuse the connection
    if (this.socket?.connected && this.authenticated) {
      console.log('✅ Socket already connected and authenticated - reusing connection');
      return Promise.resolve();
    }

    // If socket exists but not connected, don't create a new one - let it reconnect
    if (this.socket && !this.socket.connected) {
      console.log('⏳ Socket exists but disconnected - waiting for reconnection...');
      return new Promise((resolve, reject) => {
        const timeout = setTimeout(() => {
          reject(new Error('Reconnection timeout'));
        }, 5000);

        this.socket!.once('authenticated', () => {
          clearTimeout(timeout);
          resolve();
        });
      });
    }

    return new Promise((resolve, reject) => {
      console.log('🔌 Creating new Socket.IO connection:', SOCKET_URL);

      this.socket = io(SOCKET_URL, {
        transports: ['websocket', 'polling'],
        reconnection: true,
        reconnectionDelay: 1000,
        reconnectionAttempts: this.maxReconnectAttempts,
        timeout: 10000,
      });

      this.userId = userId;
      this.userType = userType;

      // Connection timeout
      const connectionTimeout = setTimeout(() => {
        if (!this.connected || !this.authenticated) {
          console.warn('⚠️ Socket connection/authentication timeout');
          this.disconnect(); // Ensure we clean up if we timeout
          reject(new Error('Connection/Authentication timeout'));
        }
      }, 5000); // Reduced to 5s for faster fallback

      this.socket.on('connect', () => {
        console.log('✅ Socket connected:', this.socket?.id);
        this.connected = true;
        this.reconnectAttempts = 0;

        // Authenticate
        this.socket?.emit('authenticate', { userId, userType });
      });

      this.socket.on('authenticated', (data) => {
        clearTimeout(connectionTimeout);
        console.log('✅ Socket authenticated:', data);
        this.authenticated = true;
        this.emit('authenticated', data);
        resolve();
      });

      this.socket.on('disconnect', (reason) => {
        console.log('❌ Socket disconnected:', reason);
        this.connected = false;
        this.authenticated = false;
        this.emit('disconnected', { reason });
      });

      this.socket.on('error', (error) => {
        console.error('❌ Socket error:', error);
        this.emit('error', error);
        reject(error);
      });

      this.socket.on('connect_error', (error) => {
        console.error('❌ Connection error:', error);
        this.reconnectAttempts++;

        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
          console.error('❌ Max reconnection attempts reached');
          reject(new Error('Failed to connect after multiple attempts'));
        }

        this.emit('connect_error', error);
      });

      // Chat events
      this.socket.on('new_message', (data) => {
        console.log('📨 New message received:', data);
        this.emit('new_message', data);
      });

      this.socket.on('message_notification', (data) => {
        console.log('🔔 [SOCKET] message_notification event received from server:', data);
        this.emit('message_notification', data);
      });

      this.socket.on('user_typing', (data) => {
        this.emit('user_typing', data);
      });

      this.socket.on('message_read', (data) => {
        this.emit('message_read', data);
      });

      this.socket.on('messages_read', (data) => {
        this.emit('messages_read', data);
      });

      this.socket.on('user_status', (data) => {
        this.emit('user_status', data);
      });

      this.socket.on('joined_conversation', (data) => {
        console.log('✅ Joined conversation:', data);
        this.emit('joined_conversation', data);
      });

      this.socket.on('message_edited', (data) => {
        this.emit('message_edited', data);
      });

      this.socket.on('message_reacted', (data) => {
        this.emit('message_reacted', data);
      });

      this.socket.on('message_pinned', (data) => {
        this.emit('message_pinned', data);
      });

      this.socket.on('conversation_pinned', (data) => {
        this.emit('conversation_pinned', data);
      });

      this.socket.on('conversation_muted', (data) => {
        this.emit('conversation_muted', data);
      });

      this.socket.on('conversation_deleted', (data) => {
        this.emit('conversation_deleted', data);
      });

      // Staff events
      this.socket.on('staff_updated', (data) => {
        console.log('👤 Staff updated event received:', data);
        this.emit('staff_updated', data);
      });
    });
  }

  disconnect(): void {
    if (this.socket) {
      console.log('🔌 Disconnecting socket...');
      this.socket.disconnect();
      this.socket = null;
      this.connected = false;
      this.authenticated = false;
      this.userId = null;
      this.userType = null;
      this.listeners.clear();
    }
  }

  // Join a conversation room
  joinConversation(conversationId: string): void {
    if (!this.socket?.connected) {
      console.error('❌ Socket not connected');
      return;
    }

    console.log('📥 Joining conversation:', conversationId);
    this.socket.emit('join_conversation', { conversationId });
  }

  // Leave a conversation room
  leaveConversation(conversationId: string): void {
    if (!this.socket?.connected) {
      console.error('❌ Socket not connected');
      return;
    }

    console.log('📤 Leaving conversation:', conversationId);
    this.socket.emit('leave_conversation', { conversationId });
  }

  // Send a message
  sendMessage(data: {
    conversationId: string;
    receiverId: string;
    receiverModel: 'Staff' | 'Student';
    content: string;
    type?: 'text' | 'image' | 'file' | 'audio' | 'video';
    fileUrl?: string;
    fileName?: string;
    fileSize?: number;
    replyTo?: {
      messageId: string;
      content: string;
      senderId: string;
      senderName: string;
    };
    forwardedFrom?: any;
  }): void {
    if (!this.socket?.connected) {
      console.error('❌ Socket not connected');
      throw new Error('Socket not connected');
    }

    console.log('📤 Sending message:', data);
    this.socket.emit('send_message', {
      ...data,
      senderId: this.userId,
      senderModel: this.userType === 'staff' ? 'Staff' : 'Student',
    });
  }

  // Send typing indicator
  sendTyping(conversationId: string, isTyping: boolean): void {
    if (!this.socket?.connected) return;

    this.socket.emit('typing', { conversationId, isTyping });
  }

  // Mark message as read
  markAsRead(messageId: string | null, conversationId: string): void {
    if (!this.socket?.connected) return;

    this.socket.emit('mark_read', { messageId, conversationId });
  }

  // Event listener management
  on(event: SocketEvent, callback: EventCallback): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }

    const callbacks = this.listeners.get(event)!;

    // Check if this exact callback already exists to prevent duplicates
    if (callbacks.includes(callback)) {
      console.log(`⚠️ [LISTENERS] Callback for '${event}' already exists, skipping duplicate`);
      return;
    }

    callbacks.push(callback);
    console.log(`📝 [LISTENERS] Added listener for '${event}', total count: ${callbacks.length}`);
  }

  off(event: SocketEvent, callback: EventCallback): void {
    if (!this.listeners.has(event)) return;

    const callbacks = this.listeners.get(event)!;
    const index = callbacks.indexOf(callback);
    if (index > -1) {
      callbacks.splice(index, 1);
    }
  }

  private emit(event: SocketEvent, data: any): void {
    if (!this.listeners.has(event)) return;

    const callbacks = this.listeners.get(event)!;
    callbacks.forEach(callback => {
      try {
        callback(data);
      } catch (error) {
        console.error(`Error in ${event} callback:`, error);
      }
    });
  }

  isConnected(): boolean {
    return this.connected && this.socket?.connected === true;
  }

  isAuthenticated(): boolean {
    return this.authenticated;
  }

  getConnectionStatus(): {
    connected: boolean;
    authenticated: boolean;
    socketId: string | undefined;
    userId: string | null;
    userType: 'staff' | 'student' | null;
    reconnectAttempts: number;
  } {
    return {
      connected: this.connected,
      authenticated: this.authenticated,
      socketId: this.socket?.id,
      userId: this.userId,
      userType: this.userType,
      reconnectAttempts: this.reconnectAttempts,
    };
  }

  // Get socket instance for direct access if needed
  getSocket(): Socket | null {
    return this.socket;
  }
}

